import sys
from kafka.admin import KafkaAdminClient, NewTopic

def create_topic(admin_client, topic_name, num_partitions=1, replication_factor=1):
    try:
        new_topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor)
        admin_client.create_topics([new_topic])
        print(f"Topic '{topic_name}' created successfully.")
    except Exception as e:
        print(f"Failed to create topic '{topic_name}': {e}")

def main():
    if len(sys.argv) < 2:
        print("Usage: python kafka_admin.py <topic_name> [num_partitions] [replication_factor]")
        sys.exit(1)

    topic_name = sys.argv[1]
    num_partitions = int(sys.argv[2]) if len(sys.argv) > 2 else 1
    replication_factor = int(sys.argv[3]) if len(sys.argv) > 3 else 1

    admin_client = KafkaAdminClient(bootstrap_servers='your_kafka_broker_address')
    create_topic(admin_client, topic_name, num_partitions, replication_factor)
    admin_client.close()

if __name__ == "__main__":
    main()